package enrich

import (
	"encoding/json"
	"fmt"
	"io"
	"os"

	"github.com/spf13/cobra"
	"github.com/usenurge/nurgesh/internal/db"
	enrichpkg "github.com/usenurge/nurgesh/internal/enrich"
)

var enrichSaveCmd = &cobra.Command{
	Use:   "save",
	Short: "Save enrichment results from stdin",
	Long: `Reads enrichment JSON from stdin and updates contacts + enrichment cache.

Accepts a single object or an array of objects:
  {
    "contact_email": "person@company.com",
    "fields": { "name": "John Doe", "title": "CTO", "company": "Acme Inc" },
    "source": "manual",
    "provider": "clearbit"
  }`,
	RunE: func(cmd *cobra.Command, args []string) error {
		stdin, _ := cmd.Flags().GetBool("stdin")
		if !stdin {
			return fmt.Errorf("--stdin flag is required")
		}

		data, err := io.ReadAll(os.Stdin)
		if err != nil {
			return fmt.Errorf("reading stdin: %w", err)
		}

		var inputs []enrichpkg.SaveInput
		if err := json.Unmarshal(data, &inputs); err != nil {
			var single enrichpkg.SaveInput
			if err2 := json.Unmarshal(data, &single); err2 != nil {
				return fmt.Errorf("parsing stdin JSON: %w", err)
			}
			inputs = []enrichpkg.SaveInput{single}
		}

		if len(inputs) == 0 {
			return fmt.Errorf("no enrichment data provided")
		}

		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		results := enrichpkg.SaveBatch(d, inputs)

		if enrichFormat == "json" {
			enc := json.NewEncoder(os.Stdout)
			enc.SetIndent("", "  ")
			return enc.Encode(results)
		}

		var updated, cached, errCount int
		for _, r := range results {
			if r.Error != "" {
				errCount++
				fmt.Fprintf(os.Stderr, "  error: %s: %s\n", r.ContactEmail, r.Error)
				continue
			}
			if r.ContactUpdated {
				updated++
			}
			if r.CacheStored {
				cached++
			}
		}

		fmt.Printf("  Processed %d enrichment(s): %d contact(s) updated, %d cached", len(results), updated, cached)
		if errCount > 0 {
			fmt.Printf(", %d error(s)", errCount)
		}
		fmt.Println()
		return nil
	},
}

var enrichSetPastCompanyCmd = &cobra.Command{
	Use:   "set-past-companies <email> <companies-json>",
	Short: "Set past companies for a contact (JSON array of company names)",
	Args:  cobra.ExactArgs(2),
	RunE: func(cmd *cobra.Command, args []string) error {
		email := args[0]
		companiesJSON := args[1]

		var companies []string
		if err := json.Unmarshal([]byte(companiesJSON), &companies); err != nil {
			return fmt.Errorf("invalid JSON array: %w", err)
		}

		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		result, err := d.Exec(
			`UPDATE contacts SET past_companies = ?, updated_at = datetime('now') WHERE lower(email) = lower(?)`,
			companiesJSON, email,
		)
		if err != nil {
			return fmt.Errorf("updating contact: %w", err)
		}

		rows, _ := result.RowsAffected()
		if rows == 0 {
			return fmt.Errorf("no contact found with email: %s", email)
		}

		if enrichFormat == "json" {
			enc := json.NewEncoder(os.Stdout)
			return enc.Encode(map[string]interface{}{
				"ok":      true,
				"email":   email,
				"updated": rows,
			})
		}

		fmt.Printf("  Updated past companies for %s\n", email)
		return nil
	},
}

