	"github.com/usenurge/nurgesh/internal/sequence"
)

var campaignsFormat string
var campaignsStatus string
var campaignsLimit int
var campaignSequence string
var campaignMailbox string
var campaignDescription string

var campaignsCmd = &cobra.Command{
	Use:   "campaigns",
	Short: "Manage campaign defaults for outbound sequences",
}

var campaignsCreateCmd = &cobra.Command{
	Use:   "create <name>",
	Short: "Create or update a campaign",
	Args:  cobra.ExactArgs(1),
	RunE: func(cmd *cobra.Command, args []string) error {
		if campaignSequence == "" {
			return fmt.Errorf("--sequence is required")
		}
		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		campaign, err := sequence.CreateCampaign(d, args[0], campaignSequence, campaignMailbox, campaignDescription)
		if err != nil {
			return err
		}
		fmt.Printf("  ✓ Saved campaign %s → %s\n", campaign.Name, campaign.SequenceName)
		if campaign.MailboxEmail != "" {
			fmt.Printf("    mailbox: %s\n", campaign.MailboxEmail)
		}
		return nil
	},
}

var campaignsListCmd = &cobra.Command{
	Use:   "list",
	Short: "List campaigns",
	RunE: func(cmd *cobra.Command, args []string) error {
		d, err := db.Open()
		if err != nil {
			return cmdutil.ErrorJSON(campaignsFormat, err)
		}
		defer d.Close()

		items, err := sequence.ListCampaigns(d, campaignsStatus, campaignsLimit)
		if err != nil {
			return cmdutil.ErrorJSON(campaignsFormat, err)
		}
		if campaignsFormat == "json" {
			enc := json.NewEncoder(os.Stdout)
			enc.SetIndent("", "  ")
			return enc.Encode(items)
		}
		if len(items) == 0 {
			fmt.Println("  No campaigns yet.")
			return nil
		}
		for _, item := range items {
			fmt.Printf("  [%s] %s → %s\n", item.Status, item.Name, item.SequenceName)
			if item.MailboxEmail != "" {
				fmt.Printf("    mailbox: %s\n", item.MailboxEmail)
			}
			if item.Description != "" {
				fmt.Printf("    %s\n", item.Description)
			}
		}
		return nil
	},
}

var campaignsPauseCmd = &cobra.Command{
	Use:   "pause <name>",
	Short: "Pause a campaign",
	Args:  cobra.ExactArgs(1),
	RunE: func(cmd *cobra.Command, args []string) error {
		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()
		if err := sequence.SetCampaignStatus(d, args[0], "paused"); err != nil {
			return err
		}
		fmt.Printf("  ✓ Paused campaign %s\n", args[0])
		return nil
	},
}

