package seq

import (
	"encoding/json"
	"fmt"
	"os"
	"time"

	"github.com/spf13/cobra"
	"github.com/usenurge/nurgesh/cmd/cmdutil"
	"github.com/usenurge/nurgesh/internal/db"
	"github.com/usenurge/nurgesh/internal/sequence"
)

var mailboxesFormat string
var mailboxSetStatus string
var mailboxSetTransportEmail string
var mailboxSetRotationGroup string
var mailboxSetWarmup string
var mailboxFirstTouchCap int
var mailboxFollowUpCap int
var mailboxReplyCap int
var mailboxMinGapMinutes int
var mailboxSendWindowStart int
var mailboxSendWindowEnd int
var mailboxSendWindowTimezone string
var mailboxReputationScore int
var mailboxPriority int
var mailboxRestartWarmup bool
var mailboxesHealthDNS bool

var mailboxesCmd = &cobra.Command{
	Use:   "mailboxes",
	Short: "Show mailbox policy and daily usage",
}

var mailboxesStatusCmd = &cobra.Command{
	Use:   "status",
	Short: "Show mailbox usage and remaining capacity",
	RunE: func(cmd *cobra.Command, args []string) error {
		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		mailboxes, err := sequence.ListMailboxes(d, time.Now())
		if err != nil {
			return err
		}

		if mailboxesFormat == "json" {
			enc := json.NewEncoder(os.Stdout)
			enc.SetIndent("", "  ")
			return enc.Encode(mailboxes)
		}

		if len(mailboxes) == 0 {
			fmt.Println("  No mailboxes tracked yet. Send an email first to create mailbox state.")
			return nil
		}

		for _, mailbox := range mailboxes {
			fmt.Printf("  [%s] %s\n", mailbox.Status, mailbox.Email)
			fmt.Printf("    transport: %s | rotation: %s\n", mailbox.TransportEmail, mailbox.RotationGroup)
			fmt.Printf("    warmup: %s | reputation: %d | priority: %d\n", mailbox.WarmupStage, mailbox.ReputationScore, mailbox.Priority)
			fmt.Printf("    send window: %02d:00-%02d:00 %s | min gap: %d min\n", mailbox.SendWindowStartHour, mailbox.SendWindowEndHour, mailbox.SendWindowTimezone, mailbox.MinGapMinutes)
			fmt.Printf("    first touches: %d/%d\n", mailbox.FirstTouchesSent, mailbox.FirstTouchDailyCap)
			fmt.Printf("    follow-ups: %d/%d\n", mailbox.FollowUpsSent, mailbox.FollowUpDailyCap)
			if mailbox.ReplyDailyCap > 0 {
				fmt.Printf("    replies: %d/%d\n", mailbox.RepliesSent, mailbox.ReplyDailyCap)
			} else {
				fmt.Printf("    replies: %d/unlimited\n", mailbox.RepliesSent)
			}
			if mailbox.LastUsedAt != "" {
				fmt.Printf("    last used: %s\n", cmdutil.ShortDate(mailbox.LastUsedAt))
			}
			if mailbox.LastBounceAt != "" {
				fmt.Printf("    last bounce: %s\n", cmdutil.ShortDate(mailbox.LastBounceAt))
			}
		}
		return nil
	},
}

var mailboxesHealthCmd = &cobra.Command{
	Use:   "health",
	Short: "Show deliverability health by mailbox",
	RunE: func(cmd *cobra.Command, args []string) error {
		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		health, err := sequence.ListMailboxHealth(d, time.Now(), mailboxesHealthDNS)
		if err != nil {
			return err
		}

		if mailboxesFormat == "json" {
			enc := json.NewEncoder(os.Stdout)
			enc.SetIndent("", "  ")
			return enc.Encode(health)
		}

		if len(health) == 0 {
			fmt.Println("  No mailboxes tracked yet. Send an email first to create mailbox state.")
			return nil
		}

		for _, item := range health {
			fmt.Printf("  [%s] %s\n", item.Risk, item.Mailbox.Email)
			fmt.Printf("    health score: %d | reputation: %d\n", item.HealthScore, item.Mailbox.ReputationScore)
			fmt.Printf("    warmup day: %d | caps: first-touch=%d follow-up=%d reply=%d\n", item.WarmupDay, item.EffectiveFirstTouchCap, item.EffectiveFollowUpCap, item.EffectiveReplyCap)
			fmt.Printf("    bounce rate (14d): %.1f%% (%d/%d)\n", item.BounceStats.BounceRate*100, item.BounceStats.Bounces, item.BounceStats.Sends)
			if item.DomainAuth != nil {
				fmt.Printf("    dns: mx=%t spf=%t dmarc=%t dkim=%s\n", item.DomainAuth.MXPresent, item.DomainAuth.SPFPresent, item.DomainAuth.DMARCPresent, item.DomainAuth.DKIMStatus)
				if item.DomainAuth.LookupError != "" {
					fmt.Printf("    dns note: %s\n", item.DomainAuth.LookupError)
				}
			}
			if item.Mailbox.LastBounceAt != "" {
				fmt.Printf("    last bounce: %s\n", cmdutil.ShortDate(item.Mailbox.LastBounceAt))
			}
		}
		return nil
	},
}

var mailboxesSetPolicyCmd = &cobra.Command{
	Use:   "set-policy <mailbox-email>",
	Short: "Update mailbox warmup, status, or daily caps",
	Args:  cobra.ExactArgs(1),
	RunE: func(cmd *cobra.Command, args []string) error {
		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		opts := sequence.MailboxPolicyOptions{
			Status:             mailboxSetStatus,
			TransportEmail:     mailboxSetTransportEmail,
			RotationGroup:      mailboxSetRotationGroup,
			WarmupStage:        mailboxSetWarmup,
			SendWindowTimezone: mailboxSendWindowTimezone,
			RestartWarmup:      mailboxRestartWarmup,
		}
		if mailboxFirstTouchCap >= 0 {
			opts.FirstTouchDailyCap = &mailboxFirstTouchCap
		}
		if mailboxFollowUpCap >= 0 {
			opts.FollowUpDailyCap = &mailboxFollowUpCap
		}
		if mailboxReplyCap >= 0 {
			opts.ReplyDailyCap = &mailboxReplyCap
		}
		if mailboxMinGapMinutes >= 0 {
			opts.MinGapMinutes = &mailboxMinGapMinutes
		}
		if mailboxSendWindowStart >= 0 {
			opts.SendWindowStartHour = &mailboxSendWindowStart
		}
		if mailboxSendWindowEnd >= 0 {
			opts.SendWindowEndHour = &mailboxSendWindowEnd
		}
		if mailboxReputationScore >= 0 {
			opts.ReputationScore = &mailboxReputationScore
		}
		if mailboxPriority >= 0 {
			opts.Priority = &mailboxPriority
		}

		mailbox, err := sequence.UpdateMailboxPolicy(d, args[0], opts)
		if err != nil {
			return err
		}

		fmt.Printf("  ✓ Updated %s\n", mailbox.Email)
		fmt.Printf("    status: %s | warmup: %s\n", mailbox.Status, mailbox.WarmupStage)
		fmt.Printf("    transport: %s | rotation: %s\n", mailbox.TransportEmail, mailbox.RotationGroup)
		fmt.Printf("    caps: first-touch=%d follow-up=%d reply=%d\n", mailbox.FirstTouchDailyCap, mailbox.FollowUpDailyCap, mailbox.ReplyDailyCap)
		fmt.Printf("    send window: %02d:00-%02d:00 %s\n", mailbox.SendWindowStartHour, mailbox.SendWindowEndHour, mailbox.SendWindowTimezone)
		fmt.Printf("    min gap: %d minutes | reputation: %d | priority: %d\n", mailbox.MinGapMinutes, mailbox.ReputationScore, mailbox.Priority)
		return nil
	},
}

func init() {
	mailboxesCmd.PersistentFlags().StringVar(&mailboxesFormat, "format", "", "Output format (json)")
	mailboxesSetPolicyCmd.Flags().StringVar(&mailboxSetStatus, "status", "", "Mailbox status (active, paused, unhealthy)")
	mailboxesSetPolicyCmd.Flags().StringVar(&mailboxSetTransportEmail, "transport-email", "", "Transport identity used to send mail for this mailbox")
	mailboxesSetPolicyCmd.Flags().StringVar(&mailboxSetRotationGroup, "rotation-group", "", "Rotation group used for mailbox fallback")
	mailboxesSetPolicyCmd.Flags().StringVar(&mailboxSetWarmup, "warmup", "", "Warmup stage label")
	mailboxesSetPolicyCmd.Flags().IntVar(&mailboxFirstTouchCap, "first-touch-cap", -1, "First-touch emails allowed per day")
	mailboxesSetPolicyCmd.Flags().IntVar(&mailboxFollowUpCap, "follow-up-cap", -1, "Follow-up emails allowed per day")
	mailboxesSetPolicyCmd.Flags().IntVar(&mailboxReplyCap, "reply-cap", -1, "Reply emails allowed per day (0 = unlimited)")
	mailboxesSetPolicyCmd.Flags().IntVar(&mailboxMinGapMinutes, "min-gap-minutes", -1, "Minimum minutes between sends")
	mailboxesSetPolicyCmd.Flags().IntVar(&mailboxSendWindowStart, "send-window-start", -1, "Allowed send window start hour in mailbox timezone (0-23)")
	mailboxesSetPolicyCmd.Flags().IntVar(&mailboxSendWindowEnd, "send-window-end", -1, "Allowed send window end hour in mailbox timezone (0-23)")
	mailboxesSetPolicyCmd.Flags().StringVar(&mailboxSendWindowTimezone, "send-window-timezone", "", "IANA timezone for the send window")
	mailboxesSetPolicyCmd.Flags().IntVar(&mailboxReputationScore, "reputation-score", -1, "Mailbox reputation score (0-100)")
	mailboxesSetPolicyCmd.Flags().IntVar(&mailboxPriority, "priority", -1, "Mailbox rotation priority")
	mailboxesSetPolicyCmd.Flags().BoolVar(&mailboxRestartWarmup, "restart-warmup", false, "Restart the mailbox warmup ramp from today")
	mailboxesHealthCmd.Flags().BoolVar(&mailboxesHealthDNS, "dns", true, "Include DNS auth checks for mailbox domains")
	mailboxesCmd.AddCommand(mailboxesStatusCmd)
	mailboxesCmd.AddCommand(mailboxesHealthCmd)
	mailboxesCmd.AddCommand(mailboxesSetPolicyCmd)
}

