package seq

import (
	"encoding/json"
	"fmt"
	"os"
	"time"

	"github.com/spf13/cobra"
	"github.com/usenurge/nurgesh/internal/db"
	"github.com/usenurge/nurgesh/internal/sequence"
)

var engagementFormat string
var engagementEnrollment string
var engagementStep int
var engagementType string

var engagementCmd = &cobra.Command{
	Use:   "engagement",
	Short: "Track and inspect engagement events for sequence enrollments",
}

var engagementListCmd = &cobra.Command{
	Use:   "list",
	Short: "List engagement events for an enrollment",
	RunE: func(cmd *cobra.Command, args []string) error {
		if engagementEnrollment == "" {
			return fmt.Errorf("--enrollment is required")
		}

		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		events, err := sequence.ListEngagement(d, engagementEnrollment)
		if err != nil {
			return err
		}

		if engagementFormat == "json" {
			enc := json.NewEncoder(os.Stdout)
			enc.SetIndent("", "  ")
			return enc.Encode(events)
		}

		if len(events) == 0 {
			fmt.Println("  No engagement events recorded.")
			return nil
		}

		for _, e := range events {
			fmt.Printf("  [step %d] %s at %s\n", e.StepNumber, e.EventType, e.OccurredAt)
			if e.EventData != "" && e.EventData != "{}" {
				fmt.Printf("    data: %s\n", e.EventData)
			}
		}
		return nil
	},
}

var engagementRecordCmd = &cobra.Command{
	Use:   "record",
	Short: "Record an engagement event",
	RunE: func(cmd *cobra.Command, args []string) error {
		if engagementEnrollment == "" {
			return fmt.Errorf("--enrollment is required")
		}
		if engagementStep < 1 {
			return fmt.Errorf("--step is required and must be >= 1")
		}
		if engagementType == "" {
			return fmt.Errorf("--type is required (open, click, reply, bounce, ooo, unsubscribe)")
		}

		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		occurredAt := time.Now().UTC().Format(time.RFC3339)

		if err := sequence.RecordEngagement(d, engagementEnrollment, engagementStep, engagementType, "{}", occurredAt); err != nil {
			return err
		}

		if engagementFormat == "json" {
			enc := json.NewEncoder(os.Stdout)
			enc.SetIndent("", "  ")
			return enc.Encode(map[string]any{
				"enrollment_id": engagementEnrollment,
				"step":          engagementStep,
				"type":          engagementType,
				"occurred_at":   occurredAt,
				"status":        "recorded",
			})
		}

		fmt.Printf("  Recorded %s event for enrollment %s step %d\n", engagementType, engagementEnrollment, engagementStep)
		return nil
	},
}

var engagementSummaryCmd = &cobra.Command{
	Use:   "summary",
	Short: "Show engagement summary for an enrollment",
	RunE: func(cmd *cobra.Command, args []string) error {
		if engagementEnrollment == "" {
			return fmt.Errorf("--enrollment is required")
		}

		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		summary, err := sequence.EngagementSummaryForEnrollment(d, engagementEnrollment)
		if err != nil {
			return err
		}

		if engagementFormat == "json" {
			enc := json.NewEncoder(os.Stdout)
			enc.SetIndent("", "  ")
			return enc.Encode(summary)
		}

		if summary.TotalEvents == 0 {
			fmt.Println("  No engagement events recorded.")
			return nil
		}

		fmt.Printf("  Enrollment: %s\n", summary.EnrollmentID)
		fmt.Printf("  Total events: %d\n", summary.TotalEvents)
		fmt.Println()

		fmt.Println("  By type:")
		for typ, count := range summary.ByType {
			fmt.Printf("    %s: %d\n", typ, count)
		}
		fmt.Println()

		fmt.Println("  By step:")
		for stepNum, step := range summary.ByStep {
			fmt.Printf("    Step %d: %d total", stepNum, step.Total)
			parts := []string{}
			if step.Opens > 0 {
				parts = append(parts, fmt.Sprintf("%d opens", step.Opens))
			}
			if step.Clicks > 0 {
				parts = append(parts, fmt.Sprintf("%d clicks", step.Clicks))
			}
			if step.Replies > 0 {
				parts = append(parts, fmt.Sprintf("%d replies", step.Replies))
			}
			if step.Bounces > 0 {
				parts = append(parts, fmt.Sprintf("%d bounces", step.Bounces))
			}
			if step.OOOs > 0 {
				parts = append(parts, fmt.Sprintf("%d OOOs", step.OOOs))
			}
			if len(parts) > 0 {
				fmt.Printf(" (%s)", joinParts(parts))
			}
			fmt.Println()
		}

		return nil
	},
}

func joinParts(parts []string) string {
	result := ""
	for i, p := range parts {
		if i > 0 {
			result += ", "
		}
		result += p
	}
	return result
}

func init() {
	engagementCmd.PersistentFlags().StringVar(&engagementFormat, "format", "", "Output format (json)")
	engagementCmd.PersistentFlags().StringVar(&engagementEnrollment, "enrollment", "", "Enrollment ID")

	engagementRecordCmd.Flags().IntVar(&engagementStep, "step", 0, "Step number")
	engagementRecordCmd.Flags().StringVar(&engagementType, "type", "", "Event type (open, click, reply, bounce, ooo, unsubscribe)")

	engagementCmd.AddCommand(engagementListCmd)
	engagementCmd.AddCommand(engagementRecordCmd)
	engagementCmd.AddCommand(engagementSummaryCmd)
}

package seq

