	"encoding/json"
	"fmt"
	"os"
	"time"

	"github.com/spf13/cobra"
	"github.com/usenurge/nurgesh/internal/db"
	"github.com/usenurge/nurgesh/internal/sequence"
)

var analyticsFormat string

var analyticsCmd = &cobra.Command{
	Use:   "analytics",
	Short: "Show outbound sequencer analytics",
}

var analyticsSummaryCmd = &cobra.Command{
	Use:   "summary",
	Short: "Show a high-level sequencer dashboard",
	RunE: func(cmd *cobra.Command, args []string) error {
		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		summary, err := sequence.AnalyticsSummary(d, time.Now())
		if err != nil {
			return err
		}

		if analyticsFormat == "json" {
			enc := json.NewEncoder(os.Stdout)
			enc.SetIndent("", "  ")
			return enc.Encode(summary)
		}

		fmt.Printf("  Enrollments: active=%d paused=%d completed=%d stopped=%d\n",
			summary.ActiveEnrollments, summary.PausedEnrollments, summary.CompletedEnrollments, summary.StoppedEnrollments)
		fmt.Printf("  Tasks: open=%d completed=%d canceled=%d\n",
			summary.OpenTasks, summary.CompletedTasks, summary.CanceledTasks)
		fmt.Printf("  Replies=%d | suppressions=%d\n", summary.ReplyCount, summary.SuppressionCount)

		if len(summary.BySequence) > 0 {
			fmt.Println("  By sequence:")
			for _, item := range summary.BySequence {
				fmt.Printf("    %s: active=%d paused=%d completed=%d stopped=%d replies=%d open=%d\n",
					item.Name, item.ActiveEnrollments, item.PausedEnrollments, item.CompletedEnrollments, item.StoppedEnrollments, item.ReplyCount, item.OpenTasks)
			}
		}

		if len(summary.ByMailbox) > 0 {
			fmt.Println("  By mailbox today:")
			for _, item := range summary.ByMailbox {
				fmt.Printf("    %s: first-touch=%d follow-up=%d reply=%d active=%d paused=%d\n",
					item.MailboxEmail, item.FirstTouchesSent, item.FollowUpsSent, item.RepliesSent, item.ActiveEnrollments, item.PausedEnrollments)
			}
		}

		return nil
	},
}

func init() {
	analyticsCmd.PersistentFlags().StringVar(&analyticsFormat, "format", "", "Output format (json)")
	analyticsCmd.AddCommand(analyticsSummaryCmd)
}

