	repliesCmd.AddCommand(repliesListCmd)
	repliesCmd.AddCommand(repliesQueueCmd)
	repliesCmd.AddCommand(repliesDoneCmd)
	repliesCmd.AddCommand(repliesReopenCmd)
	repliesCmd.AddCommand(repliesDraftCmd)
	repliesCmd.AddCommand(repliesClassifyCmd)
}

