var repliesClassifyCmd = &cobra.Command{
	Use:   "classify",
	Short: "Reclassify reply events from stdin (JSON array)",
	Long:  `Reads a JSON array of {"id":"reply:xxx","classification":"interested"} from stdin and reclassifies each reply, triggering cascading logic.`,
	RunE: func(cmd *cobra.Command, args []string) error {
		data, err := io.ReadAll(os.Stdin)
		if err != nil {
			return fmt.Errorf("reading stdin: %w", err)
		}
		if len(data) == 0 {
			return fmt.Errorf("no input on stdin")
		}

		var entries []struct {
			ID             string `json:"id"`
			Classification string `json:"classification"`
		}
		if err := json.Unmarshal(data, &entries); err != nil {
			return fmt.Errorf("parsing JSON: %w", err)
		}

		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		reclassified := 0
		unchanged := 0
		for _, entry := range entries {
			old, err := sequence.ReclassifyReply(d, entry.ID, entry.Classification)
			if err != nil {
				return fmt.Errorf("reclassifying %s: %w", entry.ID, err)
			}
			if old != entry.Classification {
				reclassified++
			} else {
				unchanged++
			}
		}

		if repliesFormat == "json" {
			enc := json.NewEncoder(os.Stdout)
			enc.SetIndent("", "  ")
			return enc.Encode(map[string]int{"reclassified": reclassified, "unchanged": unchanged})
		}
		fmt.Printf("  Reclassified: %d | Unchanged: %d\n", reclassified, unchanged)
		return nil
	},
}

func init() {
