package enrich

import (
	"database/sql"
	"encoding/json"
	"fmt"
	"os"

	"github.com/spf13/cobra"
	"github.com/usenurge/nurgesh/cmd/cmdutil"
	"github.com/usenurge/nurgesh/internal/db"
	enrichpkg "github.com/usenurge/nurgesh/internal/enrich"
)

var enrichFormat string
var enrichProspect string
var enrichBatch bool
var enrichLimit int
var enrichStats bool

var enrichCmd = &cobra.Command{
	Use:   "enrich",
	Short: "Enrich contacts with missing data from external providers",
	Long:  "Fill missing contact fields (title, company, phone, etc.) using a waterfall of data providers.\nProviders are defined as YAML files for pluggability.",
	RunE: func(cmd *cobra.Command, args []string) error {
		if !enrichStats && !enrichBatch && enrichProspect == "" {
			return cmd.Help()
		}

		d, err := db.Open()
		if err != nil {
			return cmdutil.ErrorJSON(enrichFormat, err)
		}
		defer d.Close()

		if enrichStats {
			return runEnrichStats(d)
		}

		if enrichProspect != "" {
			return runEnrichProspect(d, enrichProspect)
		}

		if enrichBatch {
			return runEnrichBatch(d, enrichLimit)
		}

		return nil
	},
}

func runEnrichProspect(d *sql.DB, email string) error {
	result, err := enrichpkg.Enrich(d, enrichpkg.EnrichRequest{ContactEmail: email})
	if err != nil {
		return cmdutil.ErrorJSON(enrichFormat, err)
	}

	if enrichFormat == "json" {
		enc := json.NewEncoder(os.Stdout)
		enc.SetIndent("", "  ")
		return enc.Encode(result)
	}

	fmt.Printf("  Enrichment: %s\n", result.ContactEmail)
	if len(result.FieldsFilled) > 0 {
		fmt.Printf("  Filled:\n")
		for f, v := range result.FieldsFilled {
			fmt.Printf("    %s: %s\n", f, v)
		}
	}
	if len(result.FieldsMissing) > 0 {
		fmt.Printf("  Still missing: %v\n", result.FieldsMissing)
	}
	if len(result.ProvidersUsed) > 0 {
		fmt.Printf("  Providers: %v\n", result.ProvidersUsed)
	}
	if result.Cached > 0 {
		fmt.Printf("  Cached hits: %d\n", result.Cached)
	}
	if result.TotalCost > 0 {
		fmt.Printf("  Est. cost: $%.4f\n", result.TotalCost)
	}
	return nil
}

func runEnrichBatch(d *sql.DB, limit int) error {
	results, err := enrichpkg.BatchEnrich(d, limit)
	if err != nil {
		return cmdutil.ErrorJSON(enrichFormat, err)
	}

	if enrichFormat == "json" {
		enc := json.NewEncoder(os.Stdout)
		enc.SetIndent("", "  ")
		return enc.Encode(results)
	}

	if len(results) == 0 {
		fmt.Println("  No contacts to enrich.")
		return nil
	}

	totalFilled := 0
	totalMissing := 0
	totalCached := 0
	var totalCost float64
	for _, r := range results {
		totalFilled += len(r.FieldsFilled)
		totalMissing += len(r.FieldsMissing)
		totalCached += r.Cached
		totalCost += r.TotalCost
	}

	fmt.Printf("  Enriched %d contact(s):\n", len(results))
	fmt.Printf("    Fields filled: %d\n", totalFilled)
	fmt.Printf("    Fields missing: %d\n", totalMissing)
	fmt.Printf("    Cache hits: %d\n", totalCached)
	if totalCost > 0 {
		fmt.Printf("    Est. cost: $%.4f\n", totalCost)
	}
	return nil
}

func runEnrichStats(d *sql.DB) error {
	stats, err := enrichpkg.Stats(d)
	if err != nil {
		return cmdutil.ErrorJSON(enrichFormat, err)
	}

	if enrichFormat == "json" {
		enc := json.NewEncoder(os.Stdout)
		enc.SetIndent("", "  ")
		return enc.Encode(stats)
	}

	fmt.Printf("  Enrichment Coverage (%d contacts)\n", stats.TotalContacts)
	fmt.Printf("  ──────────────────────────────────\n")
	fmt.Printf("  Enriched:    %d\n", stats.Enriched)
	fmt.Printf("  Unenriched:  %d\n", stats.Unenriched)
	fmt.Println()
	fmt.Println("  Field Coverage:")
	for _, field := range enrichpkg.AllEnrichableFields() {
		count := stats.FieldCoverage[field]
		pct := 0.0
		if stats.TotalContacts > 0 {
			pct = float64(count) / float64(stats.TotalContacts) * 100
		}
		fmt.Printf("    %-15s %d (%.0f%%)\n", field, count, pct)
	}
	return nil
}

func init() {
	enrichCmd.PersistentFlags().StringVar(&enrichFormat, "format", "", "Output format (json)")
	enrichCmd.Flags().StringVar(&enrichProspect, "prospect", "", "Enrich a single contact by email")
	enrichCmd.Flags().BoolVar(&enrichBatch, "batch", false, "Enrich all unenriched contacts")
	enrichCmd.Flags().IntVar(&enrichLimit, "limit", 50, "Max contacts to enrich in batch mode")
	enrichCmd.Flags().BoolVar(&enrichStats, "stats", false, "Show enrichment coverage statistics")

	enrichSearchCmd.Flags().String("keywords", "", "Search keywords")
	enrichSearchCmd.Flags().StringSlice("company", nil, "Current company IDs")
	enrichSearchCmd.Flags().StringSlice("past-company", nil, "Past company IDs")
	enrichSearchCmd.Flags().Int("max-pages", 20, "Max pages to paginate")

	enrichSaveCmd.Flags().Bool("stdin", false, "Read enrichment data from stdin (required)")

	enrichCmd.AddCommand(enrichCompanyCmd)
	enrichCmd.AddCommand(enrichPersonCmd)
	enrichCmd.AddCommand(enrichSearchCmd)
	enrichCmd.AddCommand(enrichHNCmd)
	enrichCmd.AddCommand(enrichGitHubCmd)
	enrichCmd.AddCommand(enrichSaveCmd)
	enrichCmd.AddCommand(enrichSetPastCompanyCmd)
}

