var sequenceTemplatesCmd = &cobra.Command{
	Use:   "templates",
	Short: "List and manage sequence templates",
	RunE: func(cmd *cobra.Command, args []string) error {
		return cmdutil.WithDB(func(d *sql.DB) error {
			templates, err := sequence.ListTemplates(d)
			if err != nil {
				return cmdutil.ErrorJSON(sequenceFormat, err)
			}
			if sequenceFormat == "json" {
				return cmdutil.OutputJSON(templates)
			}

		for _, template := range templates {
			fmt.Printf("  %s", template.Name)
			if template.Source != "" {
				fmt.Printf(" [%s]", template.Source)
			}
			fmt.Println()
			if template.Description != "" {
				fmt.Printf("    %s\n", template.Description)
			}
			for _, step := range template.Template.Steps {
				fmt.Printf("    step %d: %s (%s, +%s)\n", step.StepNumber, step.Name, step.SendType, step.Delay)
			}
		}
		return nil
		})
	},
}

var sequenceTemplatesAddCmd = &cobra.Command{
	Use:   "add",
	Short: "Add or update a custom sequence template from JSON",
	RunE: func(cmd *cobra.Command, args []string) error {
		if sequenceTemplateFile == "" {
			return fmt.Errorf("--file is required")
		}
		data, err := os.ReadFile(sequenceTemplateFile)
		if err != nil {
			return err
		}
		var payload struct {
			Name        string                  `json:"name"`
			Description string                  `json:"description"`
			Steps       []sequence.TemplateStep `json:"steps"`
		}
		if err := json.Unmarshal(data, &payload); err != nil {
			return fmt.Errorf("parsing template JSON: %w", err)
		}
		description := payload.Description
		if sequenceTemplateDescription != "" {
			description = sequenceTemplateDescription
		}

		return cmdutil.WithDB(func(d *sql.DB) error {
			record, err := sequence.SaveTemplate(d, sequence.Template{
				Name:  payload.Name,
				Steps: payload.Steps,
			}, description)
			if err != nil {
				return err
			}
			fmt.Printf("  ✓ Saved template %s (%d steps)\n", record.Name, len(record.Steps))
			return nil
		})
	},
}

var sequenceTemplatesDeleteCmd = &cobra.Command{
	Use:   "delete <name>",
	Short: "Delete a custom sequence template",
	Args:  cobra.ExactArgs(1),
	RunE: func(cmd *cobra.Command, args []string) error {
		return cmdutil.WithDB(func(d *sql.DB) error {
			if err := sequence.DeleteTemplate(d, args[0]); err != nil {
				return err
			}
			fmt.Printf("  ✓ Deleted template %s\n", args[0])
			return nil
		})
	},
}

func init() {
	sequenceCmd.PersistentFlags().StringVar(&sequenceFormat, "format", "", "Output format (json)")
	sequenceListCmd.Flags().StringVar(&sequenceStatus, "status", "", "Filter by status")
	sequenceListCmd.Flags().IntVar(&sequenceLimit, "limit", 0, "Max results")
	sequenceTemplatesAddCmd.Flags().StringVar(&sequenceTemplateFile, "file", "", "Path to a JSON template definition")
	sequenceTemplatesAddCmd.Flags().StringVar(&sequenceTemplateDescription, "description", "", "Optional description override")
	sequenceCmd.AddCommand(sequenceListCmd)
	sequenceTemplatesCmd.AddCommand(sequenceTemplatesAddCmd)
	sequenceTemplatesCmd.AddCommand(sequenceTemplatesDeleteCmd)
	sequenceCmd.AddCommand(sequenceTemplatesCmd)
	sequenceCmd.AddCommand(sequencePauseCmd)
	sequenceCmd.AddCommand(sequenceResumeCmd)
}

