		fmt.Printf("  ✓ Resumed campaign %s\n", args[0])
		return nil
	},
}

func init() {
	campaignsCmd.PersistentFlags().StringVar(&campaignsFormat, "format", "", "Output format (json)")
	campaignsListCmd.Flags().StringVar(&campaignsStatus, "status", "", "Filter by status")
