	campaignsCreateCmd.Flags().StringVar(&campaignSequence, "sequence", "", "Sequence template for this campaign")
	campaignsCreateCmd.Flags().StringVar(&campaignMailbox, "mailbox", "", "Default mailbox email for the campaign")
