package seq

import (
	"encoding/json"
	"fmt"
	"os"
	"strings"
	"time"

	"github.com/spf13/cobra"
	"github.com/usenurge/nurgesh/cmd/cmdutil"
	"github.com/usenurge/nurgesh/internal/db"
	"github.com/usenurge/nurgesh/internal/email"
	"github.com/usenurge/nurgesh/internal/sequence"
)

var (
	tasksFormat        string
	tasksAfterDays     int
	tasksIncludeFuture bool
	tasksLimit         int
	tasksSnoozeDays    int
	tasksCancelReason  string
)

var tasksCmd = &cobra.Command{
	Use:   "tasks",
	Short: "Show follow-up tasks",
}

var tasksListCmd = &cobra.Command{
	Use:   "list",
	Short: "List follow-up tasks",
	Long:  "Lists persisted sequence tasks when available. Falls back to inferred follow-ups from outbound email history.",
	RunE: func(cmd *cobra.Command, args []string) error {
		now := time.Now()
		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		sequenceTasks, err := sequence.ListTasks(d, sequence.TaskListOptions{
			IncludeFuture: tasksIncludeFuture,
			Limit:         tasksLimit,
			Now:           now,
		})
		if err != nil {
			return err
		}

		if len(sequenceTasks) > 0 {
			if tasksFormat == "json" {
				enc := json.NewEncoder(os.Stdout)
				enc.SetIndent("", "  ")
				return enc.Encode(sequenceTasks)
			}

			for _, task := range sequenceTasks {
				status := relativeDueStatus(task.DueAt, now)

				fmt.Printf("  [%s] %s\n", status, task.Subject)
				fmt.Printf("    task: %s (%s step %d)\n", task.ID, task.SequenceName, task.StepNumber)
				if task.CampaignName != "" {
					fmt.Printf("    campaign: %s\n", task.CampaignName)
				}
				fmt.Printf("    to: %s via %s\n", task.ContactEmail, task.MailboxEmail)
				fmt.Printf("    due: %s\n", cmdutil.ShortDate(task.DueAt))
				if task.SendStatus != "" {
					fmt.Printf("    send state: %s\n", task.SendStatus)
				}
			}
			return nil
		}

		inferredTasks, err := email.FollowUps(d, email.FollowUpOptions{
			AfterDays:     tasksAfterDays,
			Limit:         tasksLimit,
			IncludeFuture: tasksIncludeFuture,
			Now:           now,
		})
		if err != nil {
			return err
		}

		if tasksFormat == "json" {
			enc := json.NewEncoder(os.Stdout)
			enc.SetIndent("", "  ")
			return enc.Encode(inferredTasks)
		}

		if len(inferredTasks) == 0 {
			fmt.Println("  ✓ No follow-up tasks due")
			return nil
		}

		for _, task := range inferredTasks {
			status := relativeDueStatus(task.DueAt, now)

			fmt.Printf("  [%s] %s\n", status, task.Subject)
			fmt.Printf("    to: %s\n", joinRecipients(task.Recipients))
			fmt.Printf("    last sent: %s\n", cmdutil.ShortDate(task.LastSentAt))
			fmt.Printf("    follow up: %s\n", cmdutil.ShortDate(task.DueAt))
		}

		return nil
	},
}

var tasksSnoozeCmd = &cobra.Command{
	Use:   "snooze <task-id>",
	Short: "Push a sequence task into the future",
	Args:  cobra.ExactArgs(1),
	RunE: func(cmd *cobra.Command, args []string) error {
		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		task, err := sequence.SnoozeTask(d, args[0], tasksSnoozeDays)
		if err != nil {
			return err
		}

		fmt.Printf("  ✓ Snoozed %s to %s\n", task.ID, cmdutil.ShortDate(task.DueAt))
		return nil
	},
}

var tasksCancelCmd = &cobra.Command{
	Use:   "cancel <task-id>",
	Short: "Cancel a sequence task",
	Args:  cobra.ExactArgs(1),
	RunE: func(cmd *cobra.Command, args []string) error {
		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		if err := sequence.CancelTask(d, args[0], tasksCancelReason); err != nil {
			return err
		}

		fmt.Printf("  ✓ Canceled %s\n", args[0])
		return nil
	},
}

func joinRecipients(recipients []string) string {
	if len(recipients) == 0 {
		return "(unknown recipient)"
	}
	return strings.Join(recipients, ", ")
}

func relativeDueStatus(value string, now time.Time) string {
	dueAt, err := time.Parse(time.RFC3339, value)
	if err != nil {
		return "due"
	}

	delta := dueAt.Sub(now.UTC())
	if delta >= 0 {
		if delta < time.Minute {
			return "due soon"
		}
		if delta < time.Hour {
			return fmt.Sprintf("in %dm", int(delta.Round(time.Minute)/time.Minute))
		}
		if delta < 24*time.Hour {
			return fmt.Sprintf("in %dh", int(delta.Round(time.Hour)/time.Hour))
		}
		return fmt.Sprintf("in %dd", int(delta.Hours()/24))
	}

	overdue := -delta
	if overdue < time.Hour {
		return fmt.Sprintf("%dm overdue", int(overdue.Round(time.Minute)/time.Minute))
	}
	if overdue < 24*time.Hour {
		return fmt.Sprintf("%dh overdue", int(overdue.Round(time.Hour)/time.Hour))
	}
	return fmt.Sprintf("%dd overdue", int(overdue.Hours()/24))
}

func init() {
	tasksCmd.PersistentFlags().StringVar(&tasksFormat, "format", "", "Output format (json)")
	tasksListCmd.Flags().IntVar(&tasksAfterDays, "after-days", 3, "Mark follow-ups due this many days after the last outbound email")
	tasksListCmd.Flags().BoolVar(&tasksIncludeFuture, "all", false, "Include future follow-ups that are not due yet")
	tasksListCmd.Flags().IntVar(&tasksLimit, "limit", 0, "Max results")
	tasksSnoozeCmd.Flags().IntVar(&tasksSnoozeDays, "days", 1, "Number of days to push the task forward")
	tasksCancelCmd.Flags().StringVar(&tasksCancelReason, "reason", "manual cancel", "Reason recorded for cancellation")
	tasksCmd.AddCommand(tasksListCmd)
	tasksCmd.AddCommand(tasksSnoozeCmd)
	tasksCmd.AddCommand(tasksCancelCmd)
}

