)

var sendsFormat string
var sendsStatus string
var sendsLimit int

var sendsCmd = &cobra.Command{
	Use:   "sends",
	Short: "Inspect the outbound send ledger",
}

var sendsListCmd = &cobra.Command{
	Use:   "list",
	Short: "List recent send attempts",
	RunE: func(cmd *cobra.Command, args []string) error {
		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		attempts, err := sequence.ListSendAttempts(d, sendsLimit, sendsStatus)
		if err != nil {
			return err
		}
		if sendsFormat == "json" {
			enc := json.NewEncoder(os.Stdout)
			enc.SetIndent("", "  ")
			return enc.Encode(attempts)
		}
		if len(attempts) == 0 {
			fmt.Println("  No sends recorded yet.")
			return nil
		}
		for _, attempt := range attempts {
			fmt.Printf("  [%s] %s\n", attempt.Status, attempt.ContactEmail)
			fmt.Printf("    mailbox: %s | type: %s | at: %s\n", attempt.MailboxEmail, attempt.SendType, cmdutil.ShortDate(attempt.AttemptedAt))
			if attempt.Subject != "" {
				fmt.Printf("    subject: %s\n", attempt.Subject)
			}
			if attempt.MessageID != "" {
				fmt.Printf("    message: %s\n", attempt.MessageID)
			}
			if attempt.Error != "" {
				fmt.Printf("    error: %s\n", attempt.Error)
			}
		}
		return nil
	},
}

func init() {
	sendsCmd.PersistentFlags().StringVar(&sendsFormat, "format", "", "Output format (json)")
	sendsListCmd.Flags().StringVar(&sendsStatus, "status", "", "Filter by status")
	sendsListCmd.Flags().IntVar(&sendsLimit, "limit", 50, "Max results")
	sendsCmd.AddCommand(sendsListCmd)
}

