package seq

import (
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"strings"
	"time"

	"github.com/spf13/cobra"
	"github.com/usenurge/nurgesh/cmd/cmdutil"
	"github.com/usenurge/nurgesh/internal/automation"
	"github.com/usenurge/nurgesh/internal/db"
	"github.com/usenurge/nurgesh/internal/email"
	"github.com/usenurge/nurgesh/internal/project"
	"github.com/usenurge/nurgesh/internal/sequence"
	gm "google.golang.org/api/gmail/v1"
)

var dispatcherFormat string
var dispatcherLimit int
var dispatcherSyncReplies bool
var dispatcherExecute bool
var dispatcherTransportEmail string
var dispatcherInstallIntervalMinutes int
var dispatcherInstallSyncReplies bool
var dispatcherInstallTransportEmail string

type dispatcherExecutionResult struct {
	TaskID       string `json:"task_id"`
	ContactEmail string `json:"contact_email"`
	MailboxEmail string `json:"mailbox_email"`
	MessageID    string `json:"message_id,omitempty"`
	Status       string `json:"status"`
	Error        string `json:"error,omitempty"`
}

type dispatcherRunOutput struct {
	Queue   []sequence.DispatchTask     `json:"queue"`
	Results []dispatcherExecutionResult `json:"results,omitempty"`
}

var dispatcherCmd = &cobra.Command{
	Use:   "dispatcher",
	Short: "Inspect which due sequence tasks are ready to go out",
}

var dispatcherRunCmd = &cobra.Command{
	Use:   "run",
	Short: "Evaluate due sequence tasks against mailbox policy",
	RunE: func(cmd *cobra.Command, args []string) error {
		now := time.Now()

		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		var cfg *project.Config
		if dispatcherSyncReplies || dispatcherExecute || dispatcherTransportEmail != "" {
			cfg, err = project.Load()
			if err != nil {
				return fmt.Errorf("loading config: %w", err)
			}
		}

		transportEmail := strings.TrimSpace(dispatcherTransportEmail)
		if transportEmail == "" && cfg != nil {
			if gmail, ok := cfg.Connectors["gmail"]; ok && gmail.Connected {
				transportEmail = gmail.Account
			}
		}

		var gmailService *gm.Service
		if dispatcherSyncReplies || dispatcherExecute {
			if cfg == nil {
				return fmt.Errorf("Gmail config is required for dispatcher execution")
			}
			gmail, ok := cfg.Connectors["gmail"]
			if !ok || !gmail.Connected {
				return fmt.Errorf("Gmail not connected. Run: nurge connect gmail")
			}

			gmailService, err = email.NewClient("")
			if err != nil {
				return fmt.Errorf("connecting to Gmail: %w", err)
			}

			if dispatcherSyncReplies {
				if _, err := email.SyncReplies(gmailService, d, gmail.Account, now); err != nil {
					return err
				}
			}
		}

		if dispatcherExecute && transportEmail == "" {
			return fmt.Errorf("transport mailbox is required for --execute. Connect Gmail or pass --transport-email")
		}

		dispatch, err := sequence.ListDispatchTasksForTransport(d, sequence.DispatchOptions{
			Limit:          dispatcherLimit,
			Now:            now,
			TransportEmail: transportEmail,
		})
		if err != nil {
			return err
		}

		var results []dispatcherExecutionResult
		if dispatcherExecute {
			results, err = executeDispatch(gmailService, d, dispatch)
			if err != nil {
				return err
			}
		}

		if dispatcherFormat == "json" {
			enc := json.NewEncoder(os.Stdout)
			enc.SetIndent("", "  ")
			return enc.Encode(dispatcherRunOutput{
				Queue:   dispatch,
				Results: results,
			})
		}

		if len(dispatch) == 0 {
			fmt.Println("  ✓ No due tasks in the dispatcher queue")
			return nil
		}

		for _, item := range dispatch {
			state := "ready"
			if !item.Ready {
				state = "blocked"
			}
			fmt.Printf("  [%s] %s\n", state, dispatchSubject(item))
			fmt.Printf("    task: %s (%s step %d)\n", item.ID, item.SequenceName, item.StepNumber)
			via := item.MailboxEmail
			if item.SelectedMailboxEmail != "" {
				via = item.SelectedMailboxEmail
			}
			fmt.Printf("    to: %s via %s\n", item.ContactEmail, via)
			fmt.Printf("    due: %s\n", cmdutil.ShortDate(item.DueAt))
			if dispatcherExecute && item.RenderedBody != "" {
				fmt.Printf("    body: %s\n", cmdutil.Preview(item.RenderedBody, 90))
			}
			if item.BlockedReason != "" {
				fmt.Printf("    blocked: %s\n", item.BlockedReason)
			}
		}

		if dispatcherExecute {
			var sentCount int
			for _, result := range results {
				if result.Status == "sent" {
					sentCount++
				}
			}
			fmt.Printf("\n  ✓ Executed %d due task(s)\n", sentCount)
			for _, result := range results {
				fmt.Printf("    [%s] %s via %s\n", result.Status, result.ContactEmail, result.MailboxEmail)
				if result.Error != "" {
					fmt.Printf("      %s\n", result.Error)
				}
			}
		}

		return nil
	},
}

var dispatcherInstallCmd = &cobra.Command{
	Use:   "install",
	Short: "Generate a local cron/launchd wrapper for unattended dispatch",
	Long: "Writes a project-local wrapper script that runs `nurge dispatcher run --execute`\n" +
		"on a schedule, plus a launchd plist you can copy into LaunchAgents on macOS.",
	RunE: func(cmd *cobra.Command, args []string) error {
		if !project.IsNurgeProject(".") {
			return fmt.Errorf("run this from a Nurge project root")
		}

		projectRoot, err := filepath.Abs(".")
		if err != nil {
			return fmt.Errorf("resolving project root: %w", err)
		}
		executablePath, err := os.Executable()
		if err != nil {
			return fmt.Errorf("resolving nurge executable: %w", err)
		}

		assets, err := automation.WriteDispatcherAssets(automation.DispatcherOptions{
			ProjectRoot:     projectRoot,
			ExecutablePath:  executablePath,
			IntervalMinutes: dispatcherInstallIntervalMinutes,
			SyncReplies:     dispatcherInstallSyncReplies,
			TransportEmail:  dispatcherInstallTransportEmail,
		})
		if err != nil {
			return err
		}

		if dispatcherFormat == "json" {
			enc := json.NewEncoder(os.Stdout)
			enc.SetIndent("", "  ")
			return enc.Encode(assets)
		}

		fmt.Println("  ✓ Generated unattended dispatcher assets")
		fmt.Printf("    script: %s\n", assets.ScriptPath)
		fmt.Printf("    log: %s\n", assets.LogPath)
		fmt.Printf("    launchd: %s\n", assets.LaunchdPlistPath)

		if assets.CronLine != "" {
			fmt.Println()
			fmt.Println("  Cron")
			fmt.Printf("    %s\n", assets.CronLine)
		} else {
			fmt.Println()
			fmt.Printf("  Cron\n    no exact cron expression for %d-minute intervals; use launchd or adjust manually\n", assets.IntervalMinutes)
		}

		fmt.Println()
		fmt.Println("  macOS launchd")
		if assets.LaunchdInstallPath != "" {
			fmt.Printf("    cp %s %s\n", shellSnippet(assets.LaunchdPlistPath), shellSnippet(assets.LaunchdInstallPath))
			fmt.Printf("    launchctl bootout gui/$(id -u) %s 2>/dev/null || true\n", shellSnippet(assets.LaunchdInstallPath))
			fmt.Printf("    launchctl bootstrap gui/$(id -u) %s\n", shellSnippet(assets.LaunchdInstallPath))
		} else {
			fmt.Printf("    copy %s into ~/Library/LaunchAgents/%s.plist\n", assets.LaunchdPlistPath, assets.LaunchdLabel)
		}

		fmt.Println()
		fmt.Println("  Note")
		fmt.Println("    This is local unattended execution: the terminal can be closed, but the machine must stay on and your auth must remain valid.")

		return nil
	},
}

func init() {
	dispatcherCmd.PersistentFlags().StringVar(&dispatcherFormat, "format", "", "Output format (json)")
	dispatcherRunCmd.Flags().IntVar(&dispatcherLimit, "limit", 0, "Max results")
	dispatcherRunCmd.Flags().BoolVar(&dispatcherSyncReplies, "sync-replies", true, "Sync active-thread replies before evaluating the queue")
	dispatcherRunCmd.Flags().BoolVar(&dispatcherExecute, "execute", false, "Render and send ready tasks automatically")
	dispatcherRunCmd.Flags().StringVar(&dispatcherTransportEmail, "transport-email", "", "Transport mailbox to use for execution/rotation (defaults to connected Gmail account)")
	dispatcherInstallCmd.Flags().IntVar(&dispatcherInstallIntervalMinutes, "interval-minutes", 5, "How often the unattended wrapper should run")
	dispatcherInstallCmd.Flags().BoolVar(&dispatcherInstallSyncReplies, "sync-replies", true, "Sync active-thread replies before each unattended run")
	dispatcherInstallCmd.Flags().StringVar(&dispatcherInstallTransportEmail, "transport-email", "", "Transport mailbox to pin the unattended runner to")
	dispatcherCmd.AddCommand(dispatcherRunCmd)
	dispatcherCmd.AddCommand(dispatcherInstallCmd)
}

