			enc := json.NewEncoder(os.Stdout)
			enc.SetIndent("", "  ")
			return enc.Encode(dispatcherRunOutput{
				Queue:   dispatch,
				Results: results,
			})
		}

		if len(dispatch) == 0 {
			fmt.Println("  ✓ No due tasks in the dispatcher queue")
			return nil
		}

		for _, item := range dispatch {
			state := "ready"
			if !item.Ready {
				state = "blocked"
			}
			fmt.Printf("  [%s] %s\n", state, dispatchSubject(item))
			fmt.Printf("    task: %s (%s step %d)\n", item.ID, item.SequenceName, item.StepNumber)
			via := item.MailboxEmail
			if item.SelectedMailboxEmail != "" {
				via = item.SelectedMailboxEmail
			}
			fmt.Printf("    to: %s via %s\n", item.ContactEmail, via)
			fmt.Printf("    due: %s\n", cmdutil.ShortDate(item.DueAt))
			if dispatcherExecute && item.RenderedBody != "" {
				fmt.Printf("    body: %s\n", cmdutil.Preview(item.RenderedBody, 90))
			}
			if item.BlockedReason != "" {
				fmt.Printf("    blocked: %s\n", item.BlockedReason)
			}
		}

		if dispatcherExecute {
			var sentCount int
			for _, result := range results {
				if result.Status == "sent" {
					sentCount++
				}
			}
			fmt.Printf("\n  ✓ Executed %d due task(s)\n", sentCount)
			for _, result := range results {
				fmt.Printf("    [%s] %s via %s\n", result.Status, result.ContactEmail, result.MailboxEmail)
				if result.Error != "" {
					fmt.Printf("      %s\n", result.Error)
				}
			}
		}

		return nil
		})
	},
}

