			return nil
		}

		for _, v := range versions {
			active := " "
			if v.Active {
				active = "*"
			}
			fmt.Printf("%s v%d  %s  (emails: %d, learnings: %d)\n",
				active, v.Version, v.CreatedAt, v.EmailCount, v.LearningCount)
		}
		return nil
	},
}

var skillsRollbackCmd = &cobra.Command{
	Use:   "rollback <skill-name> <version>",
	Short: "Restore a previous skill version",
