package skill

import (
	"database/sql"
	"fmt"
	"io"
	"os"
	"strings"

	"github.com/spf13/cobra"
	"github.com/usenurge/nurgesh/cmd/cmdutil"
	"github.com/usenurge/nurgesh/internal/session"
)

var learnDryRun bool

var learnCmd = &cobra.Command{
	Use:   "learn",
	Short: "Manage learnings from Claude Code sessions",
}

var learnType string
var learnFormat string
var learnSession string

var learnSaveCmd = &cobra.Command{
	Use:   "save",
	Short: "Save a learning from stdin",
	Long:  "Reads learning content from stdin and saves it to the database.",
	RunE: func(cmd *cobra.Command, args []string) error {
		if learnType == "" {
			return fmt.Errorf("--type is required (tone, icp, product, pattern, competitor, preference)")
		}

		data, err := io.ReadAll(os.Stdin)
		if err != nil {
			return fmt.Errorf("reading stdin: %w", err)
		}
		content := strings.TrimSpace(string(data))
		if content == "" {
			return fmt.Errorf("no content provided on stdin")
		}

		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		id, err := session.SaveLearning(d, learnType, content, learnSession)
		if err != nil {
			return err
		}

		fmt.Printf("Saved learning #%d (type: %s)\n", id, learnType)
		return nil
	},
}

var learnListCmd = &cobra.Command{
	Use:   "list",
	Short: "List all learnings",
	RunE: func(cmd *cobra.Command, args []string) error {
		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		learnings, err := session.ListLearnings(d, learnType)
		if err != nil {
			return err
		}

		if learnFormat == "json" {
			return session.PrintJSON(learnings)
		}

		if len(learnings) == 0 {
			fmt.Println("No learnings yet.")
			return nil
		}

		for _, l := range learnings {
			fmt.Printf("#%d [%s] %s\n   %s\n\n", l.ID, l.Type, l.CreatedAt, l.Content)
		}
		return nil
	},
}

var learnDistillCmd = &cobra.Command{
	Use:   "distill",
	Short: "Distill undistilled learnings into knowledge atom updates",
	Long:  "Processes learnings that haven't been distilled yet, appending them to the relevant knowledge atoms and strategic memory.",
	RunE: func(cmd *cobra.Command, args []string) error {
		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		if learnDryRun {
			// In dry-run mode, just count undistilled learnings
			learnings, err := session.ListLearnings(d, "")
			if err != nil {
				return err
			}
			// Count undistilled (we can't easily filter without the new query, but
			// we can show total and let the user know what would happen)
			fmt.Printf("  Total learnings: %d\n", len(learnings))
			fmt.Println("  Dry run — no changes made. Run without --dry-run to distill.")
			return nil
		}

		result, err := session.Distill(d)
		if err != nil {
			return err
		}

		if learnFormat == "json" {
			return session.PrintJSON(result)
		}

		if result.LearningsProcessed == 0 {
			fmt.Println("  No undistilled learnings to process.")
			return nil
		}

		fmt.Printf("  Distilled %d learnings\n", result.LearningsProcessed)
		fmt.Printf("  Atoms updated: %d\n", result.AtomsUpdated)
		fmt.Printf("  Atoms created: %d\n", result.AtomsCreated)
		if len(result.Categories) > 0 {
			fmt.Printf("  Categories: %s\n", strings.Join(result.Categories, ", "))
		}
		return nil
	},
}

func init() {
	learnSaveCmd.Flags().StringVar(&learnType, "type", "", "Learning type (tone, icp, product, pattern, competitor, preference)")
	learnSaveCmd.Flags().StringVar(&learnSession, "session", "", "Source session identifier")

	learnListCmd.Flags().StringVar(&learnType, "type", "", "Filter by learning type")
	learnListCmd.Flags().StringVar(&learnFormat, "format", "", "Output format (json)")

	learnDistillCmd.Flags().BoolVar(&learnDryRun, "dry-run", false, "Show what would be distilled without making changes")
	learnDistillCmd.Flags().StringVar(&learnFormat, "format", "", "Output format (json)")

	learnCmd.AddCommand(learnSaveCmd)
	learnCmd.AddCommand(learnListCmd)
	learnCmd.AddCommand(learnDistillCmd)
}

