package skill

import (
	"fmt"

	"github.com/spf13/cobra"
	"github.com/usenurge/nurgesh/internal/db"
	"github.com/usenurge/nurgesh/internal/session"
)

var memoryCmd = &cobra.Command{
	Use:   "memory",
	Short: "Inspect distilled strategic memory",
}

var memoryFormat string
var memoryLimit int

var memoryListCmd = &cobra.Command{
	Use:   "list",
	Short: "List recent strategic memory distilled from execution outcomes",
	RunE: func(cmd *cobra.Command, args []string) error {
		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		items, err := session.ListStrategicMemory(d, memoryLimit)
		if err != nil {
			return err
		}

		if memoryFormat == "json" {
			return session.PrintJSON(items)
		}

		if len(items) == 0 {
			fmt.Println("No strategic memory captured yet.")
			return nil
		}

		for _, item := range items {
			fmt.Printf("[%s] %s\n", item.Category, item.Summary)
			if len(item.AffectedSkills) > 0 {
				fmt.Printf("  affects: %s\n", commaJoin(item.AffectedSkills))
			}
			fmt.Printf("  seen: %s\n", item.LastSeenAt)
		}
		return nil
	},
}

func init() {
	memoryListCmd.Flags().StringVar(&memoryFormat, "format", "", "Output format (json)")
	memoryListCmd.Flags().IntVar(&memoryLimit, "limit", 10, "Maximum number of strategic memory items to show")

	memoryCmd.AddCommand(memoryListCmd)
}

func commaJoin(values []string) string {
	if len(values) == 0 {
		return ""
	}
	result := values[0]
	for i := 1; i < len(values); i++ {
		result += ", " + values[i]
	}
	return result
}

