func commaJoin(values []string) string {
	if len(values) == 0 {
		return ""
	}
	result := values[0]
	for i := 1; i < len(values); i++ {
		result += ", " + values[i]
	}
	return result
}

package pipeline

import (
	"encoding/json"
	"fmt"
	"os"
	"time"

	"github.com/spf13/cobra"
	"github.com/usenurge/nurgesh/cmd/cmdutil"
