package research

import (
	"encoding/json"
	"fmt"
	"io"
	"os"
	"strings"

	"github.com/spf13/cobra"
	"github.com/usenurge/nurgesh/internal/assembly"
	"github.com/usenurge/nurgesh/internal/db"
)

var researchFormat string

var researchCmd = &cobra.Command{
	Use:   "research",
	Short: "Manage research dossiers for prospects",
}

var saveCmd = &cobra.Command{
	Use:   "save",
	Short: "Save a research dossier from stdin",
	Long:  "Reads JSON dossier from stdin and saves it for the given prospect.",
	RunE:  runSave,
}

var getCmd = &cobra.Command{
	Use:   "get",
	Short: "Get a research dossier by prospect email",
	RunE:  runGet,
}

var listCmd = &cobra.Command{
	Use:   "list",
	Short: "List research dossiers",
	RunE:  runList,
}

func runSave(cmd *cobra.Command, args []string) error {
	prospect, _ := cmd.Flags().GetString("prospect")
	name, _ := cmd.Flags().GetString("name")
	domain, _ := cmd.Flags().GetString("domain")
	tier, _ := cmd.Flags().GetInt("tier")
	depth, _ := cmd.Flags().GetString("depth")

	if prospect == "" {
		return fmt.Errorf("--prospect is required")
	}

	// Derive domain from email if not provided
	if domain == "" {
		if parts := strings.SplitN(prospect, "@", 2); len(parts) == 2 {
			domain = parts[1]
		}
	}

	data, err := io.ReadAll(os.Stdin)
	if err != nil {
		return fmt.Errorf("reading stdin: %w", err)
	}
	if len(data) == 0 {
		return fmt.Errorf("no input provided on stdin")
	}
	if !json.Valid(data) {
		return fmt.Errorf("input must be valid JSON")
	}

	d, err := db.Open()
	if err != nil {
		return err
	}
	defer d.Close()

	if err := assembly.SaveDossier(d, prospect, name, domain, json.RawMessage(data), tier, depth); err != nil {
		return err
	}

	if researchFormat == "json" {
		enc := json.NewEncoder(os.Stdout)
		enc.SetIndent("", "  ")
		return enc.Encode(map[string]any{"saved": prospect, "tier": tier, "depth": depth})
	}
	fmt.Printf("Saved dossier for %s (tier %d, %s)\n", prospect, tier, depth)
	return nil
}

func runGet(cmd *cobra.Command, args []string) error {
	prospect, _ := cmd.Flags().GetString("prospect")

	if prospect == "" {
		return fmt.Errorf("--prospect is required")
	}

	d, err := db.Open()
	if err != nil {
		return err
	}
	defer d.Close()

	dossier, err := assembly.GetDossier(d, prospect)
	if err != nil {
		return err
	}

	if dossier == nil {
		if researchFormat == "json" {
			enc := json.NewEncoder(os.Stdout)
			enc.SetIndent("", "  ")
			return enc.Encode(map[string]any{"found": false})
		}
		fmt.Printf("No dossier found for %s\n", prospect)
		return nil
	}

	if researchFormat == "json" {
		enc := json.NewEncoder(os.Stdout)
		enc.SetIndent("", "  ")
		return enc.Encode(dossier)
	}

	fmt.Printf("  Email:   %s\n", dossier.ContactEmail)
	if dossier.ContactName != "" {
		fmt.Printf("  Name:    %s\n", dossier.ContactName)
	}
	if dossier.CompanyDomain != "" {
		fmt.Printf("  Domain:  %s\n", dossier.CompanyDomain)
	}
	fmt.Printf("  Tier:    %d\n", dossier.Tier)
	if dossier.ResearchDepth != "" {
		fmt.Printf("  Depth:   %s\n", dossier.ResearchDepth)
	}
	fmt.Printf("  Updated: %s\n", dossier.UpdatedAt)
	return nil
}

func runList(cmd *cobra.Command, args []string) error {
	domain, _ := cmd.Flags().GetString("domain")
	limit, _ := cmd.Flags().GetInt("limit")

	d, err := db.Open()
	if err != nil {
		return err
	}
	defer d.Close()

	dossiers, err := assembly.ListDossiers(d, domain, limit)
	if err != nil {
		return err
	}

	if researchFormat == "json" {
		enc := json.NewEncoder(os.Stdout)
		enc.SetIndent("", "  ")
		return enc.Encode(dossiers)
	}

	if len(dossiers) == 0 {
		fmt.Println("No dossiers found.")
		return nil
	}

	for _, ds := range dossiers {
		depth := ds.ResearchDepth
		if depth == "" {
			depth = "-"
		}
		domain := ds.CompanyDomain
		if domain == "" {
			domain = "-"
		}
		fmt.Printf("  %s  domain=%s  tier=%d  depth=%s  updated=%s\n",
			ds.ContactEmail, domain, ds.Tier, depth, ds.UpdatedAt)
	}
	return nil
}

func init() {
	researchCmd.PersistentFlags().StringVar(&researchFormat, "format", "", "Output format (json)")

	saveCmd.Flags().String("prospect", "", "Contact email (required)")
	saveCmd.Flags().String("name", "", "Contact name")
	saveCmd.Flags().String("domain", "", "Company domain (derived from email if not provided)")
	saveCmd.Flags().Int("tier", 0, "Research tier")
	saveCmd.Flags().String("depth", "deep", "Research depth label")

	getCmd.Flags().String("prospect", "", "Contact email (required)")

	listCmd.Flags().String("domain", "", "Filter by company domain")
	listCmd.Flags().Int("limit", 20, "Maximum number of results")

	researchCmd.AddCommand(saveCmd, getCmd, listCmd)
}

