func TestCancelTaskStopsEnrollment(t *testing.T) {
	d := setupTestDB(t)
	defer d.Close()

	mailbox, err := EnsureMailbox(d, "sales@example.com", "gmail")
	if err != nil {
		t.Fatal(err)
	}

	sentAt := time.Date(2026, 3, 24, 10, 0, 0, 0, time.UTC)
	enrollment, task, err := CreateEnrollmentAfterFirstTouch(d, EnrollmentOptions{
		SequenceName: DefaultTemplateName,
		MailboxID:    mailbox.ID,
		ContactEmail: "jane@target.com",
		Subject:      "Idea for TargetCo",
		SentAt:       sentAt,
	})
	if err != nil {
		t.Fatal(err)
	}

	if err := CancelTask(d, task.ID, "manual cancel"); err != nil {
		t.Fatal(err)
	}

	updatedEnrollment, err := EnrollmentByID(d, enrollment.ID)
	if err != nil {
		t.Fatal(err)
	}
	if updatedEnrollment.Status != StatusStopped {
		t.Fatalf("status = %s, want %s", updatedEnrollment.Status, StatusStopped)
	}
	if updatedEnrollment.NextDueAt != "" {
		t.Fatalf("next_due_at = %q, want empty", updatedEnrollment.NextDueAt)
	}
}

