func CancelTask(d *sql.DB, taskID, reason string) error {
	task, err := TaskByID(d, taskID)
	if err != nil {
		return err
	}

	tx, err := d.Begin()
	if err != nil {
		return fmt.Errorf("beginning transaction: %w", err)
	}
	defer tx.Rollback()

	if _, err = tx.Exec(`
		UPDATE follow_up_tasks
		SET status = ?, send_status = ?, canceled_reason = ?, updated_at = datetime('now')
		WHERE id = ?`,
		TaskStatusCanceled, TaskSendStatusFailed, reason, task.ID,
	); err != nil {
		return err
	}
	if err := UpdateDraftStatusByTaskID(d, task.ID, "canceled"); err != nil && !isNotFound(err) {
		return err
	}

	if _, err = tx.Exec(`
		UPDATE sequence_enrollments
		SET status = ?, status_reason = ?, next_due_at = '', updated_at = datetime('now')
		WHERE id = ? AND status IN (?, ?)`,
		StatusStopped, reason, task.EnrollmentID, StatusActive, StatusPaused,
	); err != nil {
		return err
	}

	return tx.Commit()
}

func MarkTaskAttempt(d *sql.DB, taskID string, attemptedAt time.Time, attemptErr error) error {
	if attemptedAt.IsZero() {
		attemptedAt = time.Now()
	}
	lastError := ""
	if attemptErr != nil {
		lastError = attemptErr.Error()
	}
	_, err := d.Exec(`
		UPDATE follow_up_tasks
		SET attempt_count = attempt_count + 1,
			last_attempt_at = ?,
			last_error = ?,
			send_status = CASE
				WHEN ? = '' THEN send_status
				ELSE ?
			END,
			updated_at = datetime('now')
		WHERE id = ?`,
		attemptedAt.UTC().Format(time.RFC3339), lastError, failedStatus(lastError), failedStatus(lastError), taskID,
	)
	return err
}

